<style>
  /* Root Theme Configuration matching the topmate aesthetic */
  :root {
    --brand-orange: #d94d43;
    --text-light: #ffffff;
    --text-dark: #222222;
    --bg-cream: #f6f4ee;
    --card-shadow: 0 4px 15px rgba(0,0,0,0.05);
  }

  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    font-family: system-ui, -apple-system, 'Segoe UI', Roboto, Helvetica, sans-serif;
    background: var(--bg-cream);
  }

  /* Core Layout splits 1/4 and 3/4 */
  .portfolio-container {
    display: grid;
    grid-template-columns: 1fr;
    min-height: 100vh;
  }

  @media (min-width: 992px) {
    .portfolio-container {
      grid-template-columns: 1.2fr 3.8fr;
    }
  }

  /* Left Panel: Core Profile Branding Sidebar */
  .profile-sidebar {
    background-color: var(--brand-orange);
    color: var(--text-light);
    padding: 3rem 2rem;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
  }

  .avatar-frame {
    width: 160px;
    height: 160px;
    border-radius: 50%;
    overflow: hidden;
    margin-bottom: 1.5rem;
    border: 3px solid rgba(255, 255, 255, 0.4);
    box-shadow: 0 4px 10px rgba(0,0,0,0.15);
  }

  .avatar-frame img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .profile-sidebar h1 {
    font-size: 2rem;
    font-weight: 700;
    margin-bottom: 0.5rem;
    color: var(--text-light);
    line-height: 1.2;
  }

  .profile-sidebar h4 {
    font-size: 1rem;
    font-weight: 400;
    opacity: 0.9;
    margin-bottom: 1.5rem;
    line-height: 1.4;
    border-bottom: 1px solid rgba(255,255,255,0.2);
    padding-bottom: 1.5rem;
    width: 100%;
  }

  /* Social Links */
  .sidebar-socials {
    display: flex;
    gap: 1.5rem;
    margin-bottom: 2rem;
    font-size: 1.5rem;
  }

  .sidebar-socials a {
    color: var(--text-light);
    opacity: 0.85;
    transition: opacity 0.2s, transform 0.2s;
  }

  .sidebar-socials a:hover {
    opacity: 1;
    transform: scale(1.1);
  }

  /* Right Panel: Main Dashboard Content Area */
  .content-showcase {
    background-color: var(--bg-cream);
    padding: 4rem 3rem;
    color: var(--text-dark);
  }

  @media (max-width: 768px) {
    .content-showcase {
      padding: 2rem 1.5rem;
    }
  }

  /* Horizontal Content-Top Navigation Menu */
  .sidebar-nav {
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-bottom: 2.5rem;
    padding-bottom: 1.5rem;
    border-bottom: 1px solid rgba(0, 0, 0, 0.08);
  }

  .sidebar-nav a {
    color: #555555;
    text-decoration: none;
    font-size: 14px;
    font-weight: 500;
    padding: 10px 20px;
    border-radius: 30px;
    background: #ffffff;
    box-shadow: 0 2px 8px rgba(0,0,0,0.02);
    border: 1px solid rgba(0, 0, 0, 0.05);
    transition: all 0.2s ease;
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
  }

  .sidebar-nav a:hover {
    color: var(--brand-orange);
    background: #ffffff;
    border-color: var(--brand-orange);
    transform: translateY(-1px);
  }

  .sidebar-nav a.active {
    color: #ffffff;
    background: var(--brand-orange);
    border-color: var(--brand-orange);
    font-weight: 600;
    box-shadow: 0 4px 12px rgba(217, 77, 67, 0.25);
  }

  .showcase-section-title {
    font-size: 1.6rem;
    font-weight: 700;
    color: var(--text-dark);
    margin-bottom: 1rem;
  }

  .showcase-subtitle {
    color: #555555;
    font-size: 15px;
    line-height: 1.6;
    margin-bottom: 1.5rem;
  }

  /* Topics Highlight Grid */
  .topics-showcase-list {
    list-style: none;
    padding-left: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-bottom: 2.5rem;
  }

  .topics-showcase-list li {
    background: #ffffff;
    border: 1px solid rgba(0, 0, 0, 0.06);
    padding: 10px 18px;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 500;
    color: var(--text-dark);
    box-shadow: 0 2px 6px rgba(0,0,0,0.01);
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
  }

  /* Newsletter Primary Dashboard Card Layout */
  .newsletter-container-card {
    background: #ffffff;
    border-radius: 16px;
    padding: 2.5rem;
    box-shadow: var(--card-shadow);
    border: 1px solid rgba(0,0,0,0.02);
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: 1.25rem;
  }

  .newsletter-container-card h3 {
    font-size: 1.4rem;
    font-weight: 700;
    color: var(--text-dark);
    margin: 0;
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
  }

  .newsletter-container-card p {
    color: #555555;
    font-size: 15px;
    line-height: 1.6;
    margin: 0;
  }

  /* LinkedIn Profile Action Style Button */
  .linkedin-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 12px 24px;
    background-color: #0a66c2;
    color: #ffffff !important;
    text-decoration: none !important;
    border-radius: 30px;
    font-size: 14px;
    font-weight: 600;
    border: none;
    cursor: pointer;
    box-shadow: 0 4px 12px rgba(10, 102, 194, 0.2);
    transition: background-color 0.2s ease, transform 0.2s ease;
  }

  .linkedin-btn:hover {
    background-color: #004182;
    transform: translateY(-1px);
    box-shadow: 0 6px 16px rgba(10, 102, 194, 0.3);
  }

  hr {
    margin: 2.5rem 0;
    border: none;
    border-top: 1px solid rgba(0,0,0,0.1);
  }
</style>
```


